ï»¿import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import './css/ProductList.css';

const ProductList = () => {
    const [products, setProducts] = useState([]);
    const [loading, setLoading] = useState(false);

    const [searchTerm, setSearchTerm] = useState('');
    const [categoryId, setCategoryId] = useState('');
    const [currentPage, setCurrentPage] = useState(1);
    const [totalPages, setTotalPages] = useState(1);

    // 1. TĂ¡ch hĂ m gá»i API riĂªng biá»‡t
    const fetchProductsData = async () => {
        setLoading(true);
        try {
            const url = `https://localhost:7263/api/products?search=${searchTerm}&categoryId=${categoryId}&page=${currentPage}&pageSize=6`;
            const response = await fetch(url);
            if (!response.ok) throw new Error('Lá»—i khi táº£i dá»¯ liá»‡u');

            const data = await response.json();
            const productArray = data.products || data.Products || [];

            setProducts(productArray);
            setTotalPages(data.totalPages || data.TotalPages || 1);
            setCurrentPage(data.currentPage || data.CurrentPage || 1);
        } catch (error) {
            console.error('Lá»—i API:', error);
            setProducts([]);
        } finally {
            setLoading(false);
        }
    };

    // 2. Tá»± Ä‘á»™ng reset trang vá» 1 khi tá»« khĂ³a hoáº·c danh má»¥c thay Ä‘á»•i
    useEffect(() => {
        setCurrentPage(1);
    }, [searchTerm, categoryId]);

    // 3. Gá»i API má»—i khi tá»« khĂ³a, danh má»¥c HOáº¶C trang thay Ä‘á»•i
    useEffect(() => {
        // Ká»¹ thuáº­t Debounce: TrĂ¡nh gá»i API liĂªn tá»¥c má»—i khi nháº¥n 1 phĂ­m
        const delayDebounceFn = setTimeout(() => {
            fetchProductsData();
        }, 400); // Äá»£i 0.4 giĂ¢y sau khi ngá»«ng gĂµ má»›i gá»i API

        return () => clearTimeout(delayDebounceFn);
    }, [searchTerm, categoryId, currentPage]);

    return (
        <div className="product-catalog-container">
            <h1 style={{ textAlign: 'center', marginBottom: '30px', color: '#333' }}>
                DANH Má»¤C THIáº¾T Bá» DÆ¯á»¢C PHáº¨M
            </h1>

            <div className="search-filter-bar">
                <input
                    type="text"
                    placeholder="Nháº­p tĂªn mĂ¡y cáº§n tĂ¬m..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="search-input"
                />

                <select
                    value={categoryId}
                    onChange={(e) => setCategoryId(e.target.value)}
                    className="filter-select"
                >
                    <option value="">-- Táº¥t cáº£ danh má»¥c --</option>
                    <option value="1">MĂ¡y Ä‘Ă³ng nang (Capsule)</option>
                    <option value="2">MĂ¡y dáº­p viĂªn (Tablet)</option>
                    <option value="3">MĂ¡y chiáº¿t rĂ³t (Liquid Filling)</option>
                </select>
                {/* NĂºt tĂ¬m kiáº¿m bĂ¢y giá» cĂ³ thá»ƒ bá» hoáº·c Ä‘á»ƒ lĂ m cáº£nh, 
                    vĂ¬ API sáº½ tá»± gá»i khi báº¡n gĂµ/chá»n */}
            </div>

            {loading ? (
                <div style={{ textAlign: 'center', marginTop: '50px' }}>Äang táº£i dá»¯ liá»‡u...</div>
            ) : products.length > 0 ? (
                <div className="product-grid">
                    {products.map(product => (
                        <div key={product.id} className="product-item">
                            <Link to={`/product/${product.id}`} className="product-link">
                                <div className="product-image-container">
                                    <img src={product.imageUrl} alt={product.name} className="product-image" />
                                </div>
                                <h3 className="product-title">{product.name}</h3>
                            </Link>
                        </div>
                    ))}
                </div>
            ) : (
                <div style={{ textAlign: 'center', marginTop: '50px', color: 'red', fontSize: '18px' }}>
                    KhĂ´ng tĂ¬m tháº¥y sáº£n pháº©m nĂ o phĂ¹ há»£p!
                </div>
            )}

            {totalPages > 1 && (
                <div className="pagination-container">
                    <button disabled={currentPage === 1} onClick={() => setCurrentPage(prev => prev - 1)} className="page-btn">
                        &laquo; TrÆ°á»›c
                    </button>
                    <span className="page-info">Trang {currentPage} / {totalPages}</span>
                    <button disabled={currentPage === totalPages} onClick={() => setCurrentPage(prev => prev + 1)} className="page-btn">
                        Sau &raquo;
                    </button>
                </div>
            )}
        </div>
    );
};

export default ProductList;
